-- file: grants/admin_grants.sql
-- =========================
-- ADMIN (authenticated with JWT claim role=admin)
-- =========================
-- No extra GRANTs needed: they rely on same privileges as players,
-- but RLS functions (is_admin()) open up admin-only actions
-- on settings and audit_log.

-- =========================
-- SERVICE ROLE (server-side, full access)
-- =========================
grant select, insert, update, delete, truncate, references, trigger
  on all tables in schema public to service_role;

grant usage, select on all sequences in schema public to service_role;
grant execute on all functions in schema public to service_role;

alter default privileges in schema public
  grant select, insert, update, delete, truncate, references, trigger
  on tables to service_role;

alter default privileges in schema public
  grant usage, select on sequences to service_role;

alter default privileges in schema public
  grant execute on functions to service_role;

-- file: grants/misc_grants.sql
-- SCHEMA USAGE
grant usage on schema public to anon, authenticated, service_role;

-- FUNCTIONS (RPCs)
grant execute on all functions in schema public to anon, authenticated, service_role;

alter default privileges in schema public
  grant execute on functions to anon, authenticated, service_role;

-- ENUM TYPES
grant usage on type public.weight_enum, public.side_enum to anon, authenticated;

-- file: grants/player_grants.sql
-- =========================
-- PLAYER (authenticated, non-admin)
-- =========================
-- Baseline read (RLS still applies)
grant select on public.games,
               public.game_lines,
               public.results,
               public.totals,
               public.users,
               public.weeks,
               public.seasons,
               public.teams
to authenticated;

-- Picks (insert/update/select all enforced by RLS)
grant select, insert, update on public.picks to authenticated;

-- Settings & audit: grant exists so queries don’t error,
-- but RLS ensures only admins actually see/modify.
grant select, insert, update, delete on public.settings, public.audit_log to authenticated;

-- Optional: anon can read games/lines (e.g., public schedule)
grant select on public.games, public.game_lines to anon;
